def get_random_puzzle():
    return random.choice(PUZZLES)

def select_puzzle_excluding(seen_ids: list[str], difficulty: str) -> tuple[dict, bool]:
    filtered = [p for p in PUZZLES if p["difficulty"] == difficulty]
    if not filtered:
        filtered = PUZZLES
        
    available = [p for p in filtered if p["id"] not in seen_ids]
    if not available:
        return random.choice(filtered), True
    return random.choice(available), False

async def get_puzzle_for_players(player_ids: list[str], redis_client, difficulty: str) -> dict:
    seen_ids = set()
    for pid in player_ids:
        player_seen = await redis_client.smembers(f"cbr:player:{pid}:seen_puzzles")
        for p_id in player_seen:
            p_str = p_id.decode('utf-8') if isinstance(p_id, bytes) else p_id
            seen_ids.add(p_str)
            
    puzzle, did_reset = select_puzzle_excluding(list(seen_ids), difficulty)
    
    if did_reset:
        for pid in player_ids:
            await redis_client.delete(f"cbr:player:{pid}:seen_puzzles")
            
    for pid in player_ids:
        await redis_client.sadd(f"cbr:player:{pid}:seen_puzzles", puzzle["id"])
        await redis_client.expire(f"cbr:player:{pid}:seen_puzzles", 86400)
        
    return puzzle
